-- ============================================================================
-- Quiz Seed: Revelation — Part 2 (Chapters 12–22)
-- 3 difficulties × 11 chapters = 176 total questions
--   kids:   3 per chapter  = 33
--   teens:  5 per chapter  = 55
--   adults: 8 per chapter  = 88
-- ============================================================================

-- ═══════════════ CHAPTERS 12–16 ═══════════════

-- ═══ Revelation Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 12, 'kids', 1, 'What did the woman in heaven look like?', 'She was clothed with the sun, the moon under her feet, and a crown of twelve stars on her head', 'She wore a simple white dress', 'She was invisible', 'She had wings like an eagle only', 'a', 'Revelation 12:1 — "A woman clothed with the sun, and the moon under her feet, and upon her head a crown of twelve stars."'),
('Revelation', 12, 'kids', 2, 'What did the great red dragon want to do to the woman''s baby?', 'The dragon wanted to eat (devour) the child as soon as it was born', 'The dragon wanted to play with the child', 'The dragon wanted to give the child a gift', 'The dragon wanted to teach the child', 'a', 'Revelation 12:4 — "And the dragon stood before the woman which was ready to be delivered, for to devour her child as soon as it was born."'),
('Revelation', 12, 'kids', 3, 'Who is the dragon?', 'The devil, also called Satan — that old serpent', 'A friendly pet', 'A made-up character', 'A guardian angel', 'a', 'Revelation 12:9 — "And the great dragon was cast out, that old serpent, called the Devil, and Satan, which deceiveth the whole world."'),
-- Teens
('Revelation', 12, 'teens', 1, 'What happened when Michael and his angels fought the dragon?', 'The dragon and his angels were defeated and cast out of heaven to the earth', 'The dragon won the battle', 'They made a peace agreement', 'The fight ended in a draw', 'a', 'Revelation 12:7-9 — "And there was war in heaven: Michael and his angels fought against the dragon; and the dragon fought and his angels, And prevailed not; neither was their place found any more in heaven."'),
('Revelation', 12, 'teens', 2, 'How did the believers overcome the dragon?', 'By the blood of the Lamb and by the word of their testimony, and they loved not their lives unto the death', 'By their own military strength', 'By hiding from him', 'By making a deal with him', 'a', 'Revelation 12:11 — "And they overcame him by the blood of the Lamb, and by the word of their testimony; and they loved not their lives unto the death."'),
('Revelation', 12, 'teens', 3, 'What did the dragon do after being cast to earth?', 'He persecuted the woman, but she was given eagle''s wings to fly to the wilderness where she was nourished for a time, times, and half a time', 'He gave up and fell asleep', 'He became kind and helpful', 'He returned to heaven peacefully', 'a', 'Revelation 12:13-14 — "When the dragon saw that he was cast unto the earth, he persecuted the woman... And to the woman were given two wings of a great eagle, that she might fly into the wilderness... where she is nourished for a time, and times, and half a time."'),
('Revelation', 12, 'teens', 4, 'Why is the devil so angry according to this chapter?', 'Because he knows he has only a short time left before his final defeat', 'Because he lost his treasure', 'Because he is hungry', 'Because he missed his friends', 'a', 'Revelation 12:12 — "Woe to the inhabiters of the earth and of the sea! for the devil is come down unto you, having great wrath, because he knoweth that he hath but a short time."'),
('Revelation', 12, 'teens', 5, 'Who does the dragon go to war against at the end of the chapter?', 'The remnant of the woman''s seed — those who keep the commandments of God and have the testimony of Jesus Christ', 'The kings of the earth', 'The angels in heaven', 'The stars in the sky', 'a', 'Revelation 12:17 — "And the dragon was wroth with the woman, and went to make war with the remnant of her seed, which keep the commandments of God, and have the testimony of Jesus Christ."'),
-- Adults
('Revelation', 12, 'adults', 1, 'Who does the sun-clothed woman represent?', 'Most likely Israel (the covenant community) — the imagery echoes Joseph''s dream (Genesis 37:9: sun, moon, twelve stars representing Jacob''s family); she gives birth to the Messiah (v.5) and her offspring are those who keep God''s commandments (v.17)', 'Mary individually', 'The Roman Empire', 'The Greek goddess Artemis', 'a', 'Revelation 12:1-2 — The sun, moon, and twelve stars echo Genesis 37:9 (Joseph''s dream of his family). The woman gives birth to the male child who will rule all nations (v.5 — Psalm 2:9), identifying her as the messianic community that produced Christ.'),
('Revelation', 12, 'adults', 2, 'What does the male child who will "rule all nations with a rod of iron" identify?', 'Jesus Christ — the language directly quotes Psalm 2:9, a messianic psalm; His being "caught up unto God, and to his throne" refers to the ascension, telescoping from birth to exaltation with no intervening ministry details', 'A future political leader', 'An angel', 'A symbolic nation', 'a', 'Revelation 12:5 — "She brought forth a man child, who was to rule all nations with a rod of iron: and her child was caught up unto God, and to his throne." Psalm 2:9 — "Thou shalt break them with a rod of iron." The birth-to-enthronement compression is characteristic of apocalyptic style.'),
('Revelation', 12, 'adults', 3, 'How does the dragon''s tail sweeping a third of the stars connect to Daniel 8:10?', 'Daniel 8:10 describes a horn (Antiochus/Antichrist type) casting down stars — Revelation identifies the dragon''s pre-incarnation activity in leading a third of the angelic host into rebellion; the stars represent fallen angels who became the dragon''s army', 'Stars are literal astronomical objects', 'There is no connection to Daniel', 'The third is a random fraction', 'a', 'Revelation 12:4 — "His tail drew the third part of the stars of heaven, and did cast them to the earth." cf. Daniel 8:10. Stars as angels (cf. Revelation 1:20; Job 38:7) — the dragon''s rebellion took one-third of the angelic host with him (cf. Revelation 12:7-9).'),
('Revelation', 12, 'adults', 4, 'What is the theological significance of Michael''s victory over Satan in heaven?', 'It represents the decisive spiritual consequence of Christ''s death and resurrection — Satan''s role as "the accuser of our brethren" (v.10) is terminated because the blood of the Lamb has answered every accusation; the heavenly courtroom is closed to the prosecutor', 'Michael acts independently of Christ', 'The battle is purely future', 'Satan has never had access to heaven', 'a', 'Revelation 12:10-11 — "The accuser of our brethren is cast down, which accused them before our God day and night. And they overcame him by the blood of the Lamb." Satan''s expulsion from heaven is the spiritual consequence of Christ''s atonement rendering his accusations groundless (cf. Romans 8:33-34).'),
('Revelation', 12, 'adults', 5, 'How does "they overcame him by the blood of the Lamb, by the word of their testimony, and they loved not their lives unto the death" present a threefold victory strategy?', 'The blood of the Lamb (objective atonement — Christ''s finished work), the word of their testimony (subjective confession — their faithful witness), and sacrificial courage (willingness to die) — combining divine provision, personal faith, and radical commitment', 'Only the blood matters', 'Only testimony matters', 'Only courage matters', 'a', 'Revelation 12:11 — Three elements: (1) the blood of the Lamb — the objective ground of victory, (2) the word of their testimony — active faith expressed, (3) loving not their lives unto death — willingness to suffer martyrdom. All three are necessary for overcoming.'),
('Revelation', 12, 'adults', 6, 'What does the wilderness nourishment of the woman for 1,260 days signify?', 'Divine provision during persecution — echoing Israel''s wilderness sustenance (Exodus 16) and Elijah''s wilderness provision (1 Kings 17:2-6; 19:4-8); the covenant community is divinely sustained through the tribulation period, not raptured from it', 'A literal camping trip', 'Exile from God''s presence', 'Punishment for sin', 'a', 'Revelation 12:6,14 — "The woman fled into the wilderness, where she hath a place prepared of God, that they should feed her there a thousand two hundred and threescore days." God prepares a place of sustenance during the 3½-year period of persecution.'),
('Revelation', 12, 'adults', 7, 'How does the serpent''s flood from his mouth and the earth swallowing it function symbolically?', 'The flood represents satanic persecution (cf. Psalm 124:4-5 — floodwaters as hostile forces) and the earth swallowing it echoes Numbers 16:32 (the earth swallowing Korah) — God uses natural and providential means to protect His persecuted people', 'It describes a literal weather event', 'The earth is an enemy of the woman', 'The flood has no meaning', 'a', 'Revelation 12:15-16 — "The serpent cast out of his mouth water as a flood after the woman... And the earth helped the woman, and the earth opened her mouth, and swallowed up the flood." The created order serves God''s protective purposes against satanic assault.'),
('Revelation', 12, 'adults', 8, 'How does chapter 12 function as the theological centre of Revelation?', 'It provides the cosmic backstory — the ancient conflict between the dragon and the messianic community, from the birth of Christ to the end; it explains why the church suffers (the dragon''s wrath), how victory is secured (the Lamb''s blood), and what limits the persecution (a short time)', 'It is peripheral to the main story', 'It is unrelated to the surrounding chapters', 'It is purely historical narrative', 'a', 'Chapter 12 is widely regarded as the theological heart of Revelation. It resets the narrative to reveal the cosmic conflict underlying all earthly events: Satan vs. God''s people, with Christ''s death-and-resurrection as the decisive turning point.');

-- ═══ Revelation Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 13, 'kids', 1, 'What came up out of the sea?', 'A beast with seven heads and ten horns and crowns, and a blasphemous name on its heads', 'A friendly whale', 'A beautiful fish', 'A group of dolphins', 'a', 'Revelation 13:1 — "And I stood upon the sand of the sea, and saw a beast rise up out of the sea, having seven heads and ten horns, and upon his horns ten crowns, and upon his heads the name of blasphemy."'),
('Revelation', 13, 'kids', 2, 'What number is linked to the second beast?', '666 — the number of the beast, which is the number of a man', '777', '100', '12', 'a', 'Revelation 13:18 — "Here is wisdom. Let him that hath understanding count the number of the beast: for it is the number of a man; and his number is Six hundred threescore and six."'),
('Revelation', 13, 'kids', 3, 'Did the beast want people to worship him?', 'Yes, the dragon gave the beast his power, and all the world wondered after the beast and worshipped him', 'No, the beast was humble', 'The beast did not care', 'Only a few people worshipped him', 'a', 'Revelation 13:3-4 — "And all the world wondered after the beast. And they worshipped the dragon which gave power unto the beast: and they worshipped the beast."'),
-- Teens
('Revelation', 13, 'teens', 1, 'What power did the dragon give to the sea beast?', 'His power, his throne, and great authority — the beast became the dragon''s agent on earth', 'No power at all', 'Only the power to speak', 'Only the power to swim', 'a', 'Revelation 13:2 — "And the dragon gave him his power, and his seat, and great authority."'),
('Revelation', 13, 'teens', 2, 'What did the beast blaspheme?', 'God''s name, His tabernacle, and them that dwell in heaven', 'Only the earthly temples', 'Only human leaders', 'Nothing at all', 'a', 'Revelation 13:6 — "And he opened his mouth in blasphemy against God, to blaspheme his name, and his tabernacle, and them that dwell in heaven."'),
('Revelation', 13, 'teens', 3, 'What did the second beast (from the earth) do?', 'He exercised the first beast''s authority, made the earth worship the first beast, did great wonders including fire from heaven, and made an image of the beast', 'He fought against the first beast', 'He freed all the captives', 'He preached the gospel', 'a', 'Revelation 13:12-14 — "He exerciseth all the power of the first beast before him, and causeth the earth... to worship the first beast... he maketh fire come down from heaven... saying to them that dwell on the earth, that they should make an image to the beast."'),
('Revelation', 13, 'teens', 4, 'What was the mark of the beast used for?', 'No one could buy or sell unless they had the mark, the name of the beast, or the number of his name', 'It was a badge of honour', 'It was a fashion accessory', 'It had no practical use', 'a', 'Revelation 13:17 — "And that no man might buy or sell, save he that had the mark, or the name of the beast, or the number of his name."'),
('Revelation', 13, 'teens', 5, 'How long was the beast given authority?', 'Forty-two months', 'Seven years', 'Three days', 'One hundred years', 'a', 'Revelation 13:5 — "And there was given unto him a mouth speaking great things and blasphemies; and power was given unto him to continue forty and two months."'),
-- Adults
('Revelation', 13, 'adults', 1, 'How does the sea beast combine features of Daniel''s four beasts?', 'It has a leopard''s body, bear''s feet, lion''s mouth, and ten horns — merging Daniel 7''s four successive empires into one composite entity; the beast represents the totality of anti-God political power throughout history, culminating in an end-times manifestation', 'It only resembles one of Daniel''s beasts', 'There is no connection to Daniel', 'Daniel''s beasts are friendly', 'a', 'Revelation 13:2 — "The beast... was like unto a leopard, and his feet were as the feet of a bear, and his mouth as the mouth of a lion." Daniel 7 presents four separate beasts (lion, bear, leopard, ten-horned); Revelation combines all four into one — the ultimate synthesis of anti-God power.'),
('Revelation', 13, 'adults', 2, 'What does the beast''s "deadly wound that was healed" parody?', 'Christ''s death and resurrection — the beast mimics the Lamb "as it had been slain" (5:6); its recovery from a mortal wound is a satanic counterfeit of resurrection that generates worldwide wonder and worship, forming an unholy trinity (dragon, beast, false prophet) mirroring Father, Son, Holy Spirit', 'It describes a medical miracle', 'It has no christological parallel', 'It refers to a real animal injury', 'a', 'Revelation 13:3 — "One of his heads as it were wounded to death; and his deadly wound was healed: and all the world wondered after the beast." The parody of death and resurrection is central to the anti-trinity motif: dragon (anti-Father), beast (anti-Son), false prophet (anti-Spirit).'),
('Revelation', 13, 'adults', 3, 'How does the second beast (false prophet) function as an anti-Spirit?', 'As the Holy Spirit glorifies Christ and directs worship to Him (John 16:14), the false prophet glorifies the first beast and directs worship to him — he performs signs (fire from heaven echoing Elijah/Pentecost), gives breath to the image (parodying the Spirit''s life-giving work), and marks people (counterfeiting the Spirit''s seal)', 'The second beast has no religious function', 'He opposes both beasts', 'He is a positive figure', 'a', 'Revelation 13:12-15 — The second beast (later called "false prophet" — 16:13; 19:20) mirrors the Spirit''s role: glorifies another (v.12), performs signs (v.13), gives life/breath (v.15), and seals followers (vv.16-17). A comprehensive satanic counterfeit of the Spirit''s work.'),
('Revelation', 13, 'adults', 4, 'What does "it was given unto him to make war with the saints, and to overcome them" reveal?', 'The beast''s power over the saints is divinely permitted — "it was given" (edothē — divine passive) appears repeatedly, showing that even the beast''s tyranny operates within God''s sovereign permission; the saints are overcome physically but not spiritually (cf. 12:11; 15:2)', 'The saints are permanently defeated', 'God has lost control', 'The beast is stronger than God', 'a', 'Revelation 13:7 — "It was given unto him to make war with the saints, and to overcome them." The divine passive (edothē) appears six times in chapter 13 (vv.5,7[twice],14,15), showing all the beast''s authority is divinely permitted and bounded.'),
('Revelation', 13, 'adults', 5, 'What does the mark on the right hand or forehead parody?', 'It counterfeits God''s seal on the foreheads of the 144,000 (7:3; 14:1) and echoes the Shema command to bind God''s words on hand and forehead (Deuteronomy 6:8) — the beast demands the same total allegiance that God requires', 'It has no religious significance', 'It copies a Roman military tattoo', 'It parodies a medical practice', 'a', 'Revelation 13:16 — "He causeth all... to receive a mark in their right hand, or in their foreheads." This counterfeits God''s seal (7:3; 14:1) and perverts the Shema (Deuteronomy 6:8). The beast demands total devotion — in thought (forehead) and action (hand) — that belongs to God alone.'),
('Revelation', 13, 'adults', 6, 'What does 666 most likely signify?', 'It is the number of a man — falling perpetually short of seven (divine completeness); as a triple six it represents the highest human/creaturely achievement that still fails to reach the divine; if gematria is applied, "Neron Caesar" in Hebrew yields 666', 'It is an address or phone number', 'It represents perfection', 'It is a random number', 'a', 'Revelation 13:18 — "It is the number of a man; and his number is Six hundred threescore and six." The Hebrew gematria of Neron Qesar (נרון קסר) = 666. Symbolically, 6-6-6 thrice falls short of 7-7-7 — humanity aspiring to divinity but forever falling short.'),
('Revelation', 13, 'adults', 7, 'How does "Here is the patience and the faith of the saints" function?', 'It is a pastoral aside calling believers to endure — the beast''s temporary authority over buying, selling, and physical life demands patient faith that God''s ultimate victory (ch.19-20) will vindicate those who refuse the mark', 'It is a taunt against the saints', 'It has no practical application', 'It is addressed to the beast', 'a', 'Revelation 13:10 — "Here is the patience and the faith of the saints." In the face of captivity and death, believers are called to enduring trust (hypomonē) and faithfulness (pistis) — not armed resistance but spiritual perseverance under persecution.'),
('Revelation', 13, 'adults', 8, 'How does the "unholy trinity" of dragon, sea beast, and earth beast parody the Trinity?', 'The dragon mimics the Father (source of authority — v.2), the sea beast mimics the Son (receives authority, dies and "rises," is worshipped — vv.3-4), and the earth beast mimics the Spirit (directs worship, performs signs, gives "life" — vv.12-15) — a comprehensive satanic counterfeit of the divine economy', 'There is only one beast', 'The dragon and beasts have no relationship', 'This is not a parody', 'a', 'Revelation 13 presents a systematic counterfeit of the Trinity: Dragon (anti-Father: originating authority), Sea Beast (anti-Son: public figure of worship, death-resurrection parody), Earth Beast (anti-Spirit: miracle-worker directing worship to another). The structural parallel is unmistakable.');

-- ═══ Revelation Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 14, 'kids', 1, 'Who did John see standing on Mount Zion with the Lamb?', 'The 144,000 with the Father''s name written on their foreheads', 'A large army of soldiers', 'A group of angels', 'The twenty-four elders only', 'a', 'Revelation 14:1 — "And I looked, and, lo, a Lamb stood on the mount Sion, and with him an hundred forty and four thousand, having his Father''s name written in their foreheads."'),
('Revelation', 14, 'kids', 2, 'What did the angel flying in heaven have to share?', 'The everlasting gospel — good news to preach to every nation, kindred, tongue, and people', 'A scary warning only', 'A new set of rules', 'A treasure map', 'a', 'Revelation 14:6 — "And I saw another angel fly in the midst of heaven, having the everlasting gospel to preach unto them that dwell on the earth, and to every nation, and kindred, and tongue, and people."'),
('Revelation', 14, 'kids', 3, 'What did the second angel announce?', '"Babylon is fallen, is fallen, that great city"', '"The war is over"', '"The harvest is ready"', '"The flood is coming"', 'a', 'Revelation 14:8 — "And there followed another angel, saying, Babylon is fallen, is fallen, that great city, because she made all nations drink of the wine of the wrath of her fornication."'),
-- Teens
('Revelation', 14, 'teens', 1, 'What is said about the 144,000 who follow the Lamb?', 'They are not defiled, they follow the Lamb wherever He goes, they are the firstfruits unto God, and no guile was found in their mouths — they are without fault', 'They are sinful but forgiven', 'They are ordinary believers', 'They were chosen randomly', 'a', 'Revelation 14:4-5 — "These are they which were not defiled with women; for they are virgins. These are they which follow the Lamb whithersoever he goeth. These were redeemed from among men, being the firstfruits unto God and to the Lamb. And in their mouth was found no guile: for they are without fault before the throne of God."'),
('Revelation', 14, 'teens', 2, 'What does the first angel tell everyone to do?', '"Fear God, and give glory to him; for the hour of his judgment is come: and worship him that made heaven, and earth, and the sea, and the fountains of waters"', '"Hide from God"', '"Build towers"', '"Prepare for war"', 'a', 'Revelation 14:7 — "Saying with a loud voice, Fear God, and give glory to him; for the hour of his judgment is come: and worship him that made heaven, and earth, and the sea, and the fountains of waters."'),
('Revelation', 14, 'teens', 3, 'What warning does the third angel give?', 'Anyone who worships the beast and receives his mark will drink the wine of God''s wrath and be tormented with fire and brimstone', 'Those who worship the beast will be rewarded', 'The mark has no consequences', 'Only leaders will be judged', 'a', 'Revelation 14:9-10 — "If any man worship the beast and his image, and receive his mark in his forehead, or in his hand, The same shall drink of the wine of the wrath of God... and he shall be tormented with fire and brimstone."'),
('Revelation', 14, 'teens', 4, 'What does John see one "like the Son of man" do with a sickle?', 'He thrusts His sickle into the earth and reaps the harvest — the time of judgment has come', 'He cuts down a forest', 'He builds a fence', 'He plants new seeds', 'a', 'Revelation 14:14-16 — "I looked, and behold a white cloud, and upon the cloud one sat like unto the Son of man, having on his head a golden crown, and in his hand a sharp sickle... And he that sat on the cloud thrust in his sickle on the earth; and the earth was reaped."'),
('Revelation', 14, 'teens', 5, 'What happens in the "winepress of the wrath of God"?', 'The grapes (wicked) are trodden and blood comes out as high as horse bridles for 1,600 furlongs', 'Wine is made for a celebration', 'Grapes are stored for later', 'The winepress remains empty', 'a', 'Revelation 14:19-20 — "The angel thrust in his sickle into the earth, and gathered the vine of the earth, and cast it into the great winepress of the wrath of God. And the winepress was trodden without the city, and blood came out of the winepress, even unto the horse bridles, by the space of a thousand and six hundred furlongs."'),
-- Adults
('Revelation', 14, 'adults', 1, 'How does the 144,000 on Mount Zion contrast with chapter 13''s beast worshippers?', 'The 144,000 have the Father''s name on their foreheads (divine seal) versus the beast''s mark; they are on Mount Zion (God''s holy hill — Psalm 2:6) versus Babylon; they sing a new song versus blaspheming; they are firstfruits of redemption versus captives of deception', 'There is no contrast', 'Both groups are identical', 'The 144,000 are beast worshippers', 'a', 'Revelation 14:1 — The Father''s name counteracts the beast''s mark (13:16-17). Mount Zion counters the beast''s earthly throne. The new song counters the blasphemous worship. Every element is a deliberate antithesis to the counterfeit system of chapter 13.'),
('Revelation', 14, 'adults', 2, 'What does the "everlasting gospel" proclaimed by the angel contain?', 'A call to fear God, glorify Him, acknowledge the hour of judgment, and worship the Creator — it is a theocentric summons emphasising creation theology and divine judgment rather than a soteriological gospel in the Pauline sense', 'Instructions for temple worship', 'A new set of commandments', 'An invitation to a feast', 'a', 'Revelation 14:6-7 — The gospel here is "everlasting" (aiōnion) — not new content but the eternal truth of God''s creatorial claim (echoing Exodus 20:11) and sovereign judgment. Even in the final hours, the universal call to worship the Creator goes forth.'),
('Revelation', 14, 'adults', 3, 'What does "Babylon is fallen, is fallen" anticipate?', 'It is a proleptic announcement — Babylon''s detailed fall is not narrated until chapters 17-18, but the certainty of it is declared here using the prophetic perfect tense (past tense for future events); it echoes Isaiah 21:9 directly', 'Babylon has already fallen by this point', 'It refers to the historical city only', 'The repetition is a scribal error', 'a', 'Revelation 14:8 — "Babylon is fallen, is fallen" quotes Isaiah 21:9. The doubled verb emphasises certainty. This anticipatory announcement prepares readers for the detailed Babylon narrative in chapters 17-18, assuring them of the outcome before describing the process.'),
('Revelation', 14, 'adults', 4, 'What does "the wine of the wrath of God, which is poured out without mixture" mean?', 'God''s judgment is served undiluted — ancient wine was typically mixed with water to reduce potency; "without mixture" (akratos) means full-strength, unmitigated divine fury with no diluting mercy', 'It refers to actual wine', 'The mixture is irrelevant', 'It means watered-down judgment', 'a', 'Revelation 14:10 — "The same shall drink of the wine of the wrath of God, which is poured out without mixture into the cup of his indignation." Akratos (unmixed) wine was the strongest possible — God''s wrath is served at full strength with no mercy to temper it.'),
('Revelation', 14, 'adults', 5, 'How do the grain harvest and grape harvest in verses 14-20 function?', 'They likely represent two aspects of final judgment: the grain harvest (positive — gathering the righteous, cf. Matthew 13:30) by the Son of Man, and the grape harvest (negative — crushing the wicked, cf. Isaiah 63:1-6) by the angel — together depicting the comprehensive final separation', 'Both harvests are positive', 'Both harvests are negative', 'They describe agricultural practices', 'a', 'Revelation 14:14-20 — The grain harvest (vv.14-16) may represent the ingathering of the elect, while the grape harvest (vv.17-20) clearly represents judgment (the winepress of God''s wrath). Together they form a complete picture of the end: salvation and judgment.'),
('Revelation', 14, 'adults', 6, 'What does the winepress imagery draw from in the Old Testament?', 'Isaiah 63:1-6 — the divine warrior treading the winepress of the nations, staining His garments with their blood; Joel 3:13 — "Put ye in the sickle, for the harvest is ripe: come, get you down; for the press is full, the fats overflow; for their wickedness is great"', 'It draws only from Psalm 23', 'There are no Old Testament parallels', 'It echoes Genesis only', 'a', 'Revelation 14:19-20 — The winepress of God''s wrath draws from Isaiah 63:1-6 (the warrior from Edom with blood-stained garments) and Joel 3:13 (harvest and winepress as judgment metaphors). These prophetic images converge in Revelation''s final judgment scene.'),
('Revelation', 14, 'adults', 7, 'What does the 1,600 furlongs of blood signify?', 'Approximately 200 miles — possibly symbolic: 4×4×100 (four = earth, squared = totality, ×100 = completeness), representing universal, total judgment; some also note it approximates the length of the land of Israel', 'A precise geographical measurement', 'A random number', 'The exact distance to Rome', 'a', 'Revelation 14:20 — "Blood came out of the winepress, even unto the horse bridles, by the space of a thousand and six hundred furlongs." 1,600 = 4² × 10² — numbers of earthly totality and completeness, suggesting the comprehensive scope of divine judgment covering the whole earth.'),
('Revelation', 14, 'adults', 8, 'What does "Here is the patience of the saints: here are they that keep the commandments of God, and the faith of Jesus" accomplish pastorally?', 'It directly addresses persecuted believers between the warnings of judgment — encouraging endurance through the dual reality of obedience ("commandments of God") and trust ("faith of Jesus"); those who refuse the mark will face temporal suffering but eternal vindication', 'It is a legal requirement', 'It applies only to leaders', 'It has no pastoral function', 'a', 'Revelation 14:12 — This pastoral aside (cf. 13:10) positions the call to endurance between the warning of eternal punishment for beast-worshippers (vv.9-11) and the blessing of the faithful dead (v.13) — creating a framework of accountability and hope.');

-- ═══ Revelation Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 15, 'kids', 1, 'What did the seven angels have?', 'Seven last plagues — the final outpouring of God''s wrath', 'Seven trumpets', 'Seven crowns', 'Seven books', 'a', 'Revelation 15:1 — "And I saw another sign in heaven, great and marvellous, seven angels having the seven last plagues; for in them is filled up the wrath of God."'),
('Revelation', 15, 'kids', 2, 'What song did the victorious people sing?', 'The song of Moses and the song of the Lamb — praising God''s great and marvellous works', 'A lullaby', 'A song about the sea', 'A sad song about defeat', 'a', 'Revelation 15:3 — "And they sing the song of Moses the servant of God, and the song of the Lamb, saying, Great and marvellous are thy works, Lord God Almighty."'),
('Revelation', 15, 'kids', 3, 'What filled the temple so that no one could enter?', 'Smoke from the glory of God and His power', 'Water from a flood', 'Sand from a storm', 'Feathers from angels'' wings', 'a', 'Revelation 15:8 — "And the temple was filled with smoke from the glory of God, and from his power; and no man was able to enter into the temple, till the seven plagues of the seven angels were fulfilled."'),
-- Teens
('Revelation', 15, 'teens', 1, 'What were the overcomers standing on?', 'A sea of glass mingled with fire, having the harps of God', 'A green meadow', 'A cloud of gold', 'A mountain of snow', 'a', 'Revelation 15:2 — "And I saw as it were a sea of glass mingled with fire: and them that had gotten the victory over the beast, and over his image, and over his mark, and over the number of his name, stand on the sea of glass, having the harps of God."'),
('Revelation', 15, 'teens', 2, 'What did the song of Moses and the Lamb declare about God''s ways?', '"Just and true are thy ways, thou King of saints" — God''s judgments are righteous', 'God''s ways are unpredictable', 'God''s ways are unfair', 'God''s ways are confusing', 'a', 'Revelation 15:3 — "Great and marvellous are thy works, Lord God Almighty; just and true are thy ways, thou King of saints."'),
('Revelation', 15, 'teens', 3, 'What question does the song ask about God?', '"Who shall not fear thee, O Lord, and glorify thy name? for thou only art holy"', '"When will you rest?"', '"Why are you angry?"', '"Where do you live?"', 'a', 'Revelation 15:4 — "Who shall not fear thee, O Lord, and glorify thy name? for thou only art holy: for all nations shall come and worship before thee; for thy judgments are made manifest."'),
('Revelation', 15, 'teens', 4, 'What were the seven angels wearing?', 'Pure white linen and golden girdles (sashes)', 'Armour and helmets', 'Ordinary clothing', 'Red robes', 'a', 'Revelation 15:6 — "The seven angels came out of the temple, having the seven plagues, clothed in pure and white linen, and having their breasts girded with golden girdles."'),
('Revelation', 15, 'teens', 5, 'What were the seven golden vials (bowls) full of?', 'The wrath of God, who lives for ever and ever', 'Healing water', 'Holy oil', 'Sweet perfume', 'a', 'Revelation 15:7 — "And one of the four beasts gave unto the seven angels seven golden vials full of the wrath of God, who liveth for ever and ever."'),
-- Adults
('Revelation', 15, 'adults', 1, 'How does the "song of Moses and the Lamb" combine Old and New Testament themes?', 'It merges the Exodus victory song (Exodus 15 — deliverance from Egypt through the Red Sea) with the Lamb''s victory (redemption through the cross) — presenting the final deliverance as the ultimate new exodus, fulfilling the pattern established at Israel''s founding salvation event', 'It replaces the song of Moses', 'Only the Lamb''s song matters', 'The two songs are contradictory', 'a', 'Revelation 15:3 — The song combines Exodus 15 (Israel''s victory at the Red Sea) with new Lamb-centred praise. The overcomers'' victory over the beast parallels Israel''s victory over Pharaoh — the new exodus surpasses the old.'),
('Revelation', 15, 'adults', 2, 'What does the "sea of glass mingled with fire" symbolise?', 'The calm sea of chapter 4:6 is now mingled with fire — combining the throne-room''s transcendent purity with the fire of judgment and testing; the overcomers stand victorious on what represents both God''s holiness and the fiery trials they endured', 'It is a literal body of water', 'The fire is accidental', 'It has no connection to chapter 4', 'a', 'Revelation 15:2 — The "sea of glass" (cf. 4:6) now includes fire — the symbol of purification and judgment. The overcomers standing on it have passed through the fire of persecution and now stand in the place of God''s holiness.'),
('Revelation', 15, 'adults', 3, 'How does the temple filled with smoke echo Old Testament theophanies?', 'It recalls the cloud filling the tabernacle (Exodus 40:34-35) and Solomon''s temple (1 Kings 8:10-11) so that the priests could not minister — God''s overwhelming glory and judgment presence makes the temple inaccessible until the plagues are complete', 'Smoke is a sign of destruction only', 'There is no Old Testament parallel', 'The temple caught fire', 'a', 'Revelation 15:8 — "The temple was filled with smoke from the glory of God." cf. Exodus 40:34-35; 1 Kings 8:10-11; Isaiah 6:4. God''s glory-cloud rendered the holy place inaccessible — here it signals that the judgment process cannot be interrupted.'),
('Revelation', 15, 'adults', 4, 'What does "in them is filled up the wrath of God" signify about the bowls?', 'The bowls represent the final, consummating expression of divine wrath — unlike the partial seals (quarter) and trumpets (third), the bowls are total and complete; they exhaust (telesthē — brought to completion) God''s judgment on the present age', 'The bowls are mild warnings', 'They represent partial judgment', 'More judgments follow after the bowls', 'a', 'Revelation 15:1 — "Seven last plagues; for in them is filled up (etelesthē) the wrath of God." The verb teleō means "to bring to completion/perfection." These are the final judgments — after them, God''s wrath against the present evil age is exhausted.'),
('Revelation', 15, 'adults', 5, 'What does "thou only art holy" assert about God?', 'God''s absolute holiness (hosios — covenantally faithful and morally pure) is the foundation for His judgments — because He alone is truly holy, His judgments are inherently just; the claim "all nations shall come and worship" affirms that even judgment leads to the vindication of God''s character', 'Holiness is unrelated to judgment', 'Other beings share God''s holiness equally', 'It is a formal title with no meaning', 'a', 'Revelation 15:4 — "Thou only art holy (hosios)" — hosios denotes covenantal faithfulness and moral purity. The rhetorical question "Who shall not fear thee?" expects the answer "no one" — all nations will ultimately acknowledge God''s righteous judgments.'),
('Revelation', 15, 'adults', 6, 'How does chapter 15 function as a prelude to the bowl judgments?', 'It is a heavenly preparation scene — establishing the theological justification for the bowls: (1) God is just and holy (song), (2) the bowls complete His wrath (v.1), (3) the judgments come from the temple/presence of God (v.6), and (4) they cannot be interrupted (v.8)', 'It is an afterthought', 'It delays unnecessarily', 'It has no connection to chapter 16', 'a', 'Chapter 15 provides the liturgical and theological foundation for the bowls. The heavenly worship (vv.2-4) precedes heavenly judgment (vv.5-8), establishing the pattern that worship and justice are inseparable in God''s economy.'),
('Revelation', 15, 'adults', 7, 'What is the significance of the tabernacle of testimony being opened?', 'The "temple of the tabernacle of the testimony" (naos tēs skēnēs tou martyriou) links to the wilderness tabernacle housing the ark with the law tablets — judgment proceeds from the place of covenant law; those who violated God''s moral order face judgment from the very place where that order was enshrined', 'It is merely an architectural detail', 'The tabernacle is unrelated to judgment', 'It refers to a different building', 'a', 'Revelation 15:5 — "The temple of the tabernacle of the testimony in heaven was opened." The designation links to Numbers 1:50 (tabernacle of testimony). Judgment flows from the same divine presence that gave the law — covenant violation meets covenant enforcement.'),
('Revelation', 15, 'adults', 8, 'How does chapter 15 present the overcomers'' vindication before the bowls are poured?', 'By positioning the overcomers'' victory song before the judgment scene, John assures readers that the faithful are already safe and victorious in heaven before the final plagues fall on the beast''s kingdom — the outcome is settled before the process unfolds', 'The overcomers are still at risk', 'Their victory comes later', 'They have not yet overcome', 'a', 'Revelation 15:2-4 — The sequence is deliberate: vision of victorious overcomers (vv.2-4), then preparation of judgment bowls (vv.5-8). The redeemed are safe on the heavenly sea of glass before a single bowl is poured — assuring persecuted believers of their ultimate security.');

-- ═══ Revelation Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 16, 'kids', 1, 'What happened when the first bowl was poured out?', 'Painful sores appeared on people who had the mark of the beast', 'Flowers grew everywhere', 'Rain fell gently', 'Everyone fell asleep', 'a', 'Revelation 16:2 — "And the first went, and poured out his vial upon the earth; and there fell a noisome and grievous sore upon the men which had the mark of the beast, and upon them which worshipped his image."'),
('Revelation', 16, 'kids', 2, 'What happened to the sun with the fourth bowl?', 'The sun was given power to scorch people with great heat', 'The sun turned cold', 'The sun disappeared', 'The sun became brighter but harmless', 'a', 'Revelation 16:8-9 — "And the fourth angel poured out his vial upon the sun; and power was given unto him to scorch men with fire. And men were scorched with great heat."'),
('Revelation', 16, 'kids', 3, 'What fell from the sky during the seventh bowl?', 'Enormous hailstones, each weighing about a talent (around 75 pounds)', 'Soft snowflakes', 'Gentle rain', 'Colourful confetti', 'a', 'Revelation 16:21 — "And there fell upon men a great hail out of heaven, every stone about the weight of a talent: and men blasphemed God because of the plague of the hail."'),
-- Teens
('Revelation', 16, 'teens', 1, 'What happened when the second and third bowls were poured?', 'The sea became as blood and every living thing in it died; then the rivers and springs became blood', 'The waters became sweet', 'Fish multiplied in the seas', 'The waters froze solid', 'a', 'Revelation 16:3-4 — "The second angel poured out his vial upon the sea; and it became as the blood of a dead man: and every living soul died in the sea. And the third angel poured out his vial upon the rivers and fountains of waters; and they became blood."'),
('Revelation', 16, 'teens', 2, 'What did the angel of the waters say about the blood judgments?', '"Thou art righteous, O Lord... because thou hast judged thus. For they have shed the blood of saints and prophets, and thou hast given them blood to drink; for they are worthy"', '"This is too harsh"', '"Please show mercy"', '"We should wait longer"', 'a', 'Revelation 16:5-6 — "Thou art righteous, O Lord, which art, and wast, and shalt be, because thou hast judged thus. For they have shed the blood of saints and prophets, and thou hast given them blood to drink; for they are worthy."'),
('Revelation', 16, 'teens', 3, 'What happened when the fifth bowl was poured on the beast''s throne?', 'His kingdom was full of darkness and people gnawed their tongues in pain, but still they did not repent', 'His kingdom became bright', 'Everyone celebrated', 'The beast surrendered', 'a', 'Revelation 16:10-11 — "And the fifth angel poured out his vial upon the seat of the beast; and his kingdom was full of darkness; and they gnawed their tongues for pain, And blasphemed the God of heaven... and repented not of their deeds."'),
('Revelation', 16, 'teens', 4, 'What came out of the mouths of the dragon, beast, and false prophet?', 'Three unclean spirits like frogs — they are spirits of devils performing miracles to gather kings for the battle of Armageddon', 'Three doves of peace', 'Three golden coins', 'Three bright stars', 'a', 'Revelation 16:13-14 — "And I saw three unclean spirits like frogs come out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet. For they are the spirits of devils, working miracles, which go forth unto the kings of the earth and of the whole world, to gather them to the battle of that great day of God Almighty."'),
('Revelation', 16, 'teens', 5, 'What place is mentioned where the kings are gathered?', 'Armageddon — in Hebrew, Har-Magedon (the mountain of Megiddo)', 'Bethlehem', 'Nazareth', 'Rome', 'a', 'Revelation 16:16 — "And he gathered them together into a place called in the Hebrew tongue Armageddon."'),
-- Adults
('Revelation', 16, 'adults', 1, 'How do the seven bowls intensify the Egyptian plague pattern beyond the trumpets?', 'The bowls parallel the trumpets but remove the "third part" limitation — the first bowl is boils (sixth Egyptian plague), the second/third turn all water to blood (first Egyptian plague, now total), the fourth is scorching heat, the fifth is darkness (ninth Egyptian plague, now total); the escalation from partial to total judgment signals finality', 'The bowls are milder than the trumpets', 'There is no Egyptian plague connection', 'The bowls and trumpets are identical', 'a', 'Revelation 16 — Trumpets affected one-third; bowls affect totality. Bowl 1 (boils) = Exodus 9:10. Bowls 2-3 (blood) = Exodus 7:20, now universal. Bowl 5 (darkness) = Exodus 10:21, now total. The exodus pattern escalates to its final, complete expression.'),
('Revelation', 16, 'adults', 2, 'What does the angel''s declaration "thou hast given them blood to drink; for they are worthy" establish?', 'The principle of lex talionis (poetic justice) — those who shed the blood of saints and prophets receive blood to drink; the punishment matches the crime, demonstrating that God''s judgment is not arbitrary but precisely proportional and just', 'Punishment is random', 'The victims were innocent', 'Judgment is disproportionate', 'a', 'Revelation 16:6 — The lex talionis principle: blood-shedders receive blood. The word "worthy" (axioi) is bitterly ironic — they are "worthy" (deserving) of this judgment just as the Lamb was "worthy" (deserving) of worship (5:9). Divine justice mirrors the crime.'),
('Revelation', 16, 'adults', 3, 'What is the significance of the Euphrates drying up in the sixth bowl?', 'It echoes the drying of the Red Sea (Exodus 14:21) and the Jordan (Joshua 3:17), but in reverse — instead of delivering God''s people, it enables the kings of the east to gather for battle against God; it is an anti-exodus, preparing for Armageddon', 'It describes a natural drought', 'The Euphrates is irrelevant', 'It echoes Noah''s flood', 'a', 'Revelation 16:12 — "The water thereof was dried up, that the way of the kings of the east might be prepared." The Euphrates was Babylon''s defence and Rome''s eastern boundary. Its drying echoes Isaiah 11:15-16 and Jeremiah 50:38 — but here it facilitates judgment, not deliverance.'),
('Revelation', 16, 'adults', 4, 'What does "Armageddon" (Har-Magedon) mean and why is this location significant?', 'Har-Magedon means "mountain of Megiddo" — Megiddo''s valley (Jezreel/Esdraelon) was the site of decisive battles throughout Israel''s history (Judges 4-5, Deborah/Barak; 2 Kings 23:29, Josiah''s death); it symbolises the ultimate battlefield where God decisively defeats His enemies', 'It is a fictional location', 'It refers to a Roman arena', 'It means "mountain of peace"', 'a', 'Revelation 16:16 — Har = mountain; Magedon = Megiddo. The plain of Megiddo witnessed Barak''s victory over Sisera (Judges 5:19), Gideon''s victory over Midian (Judges 7), and Josiah''s death (2 Kings 23:29-30). It is the supreme symbol of decisive divine-human conflict.'),
('Revelation', 16, 'adults', 5, 'How does the parenthetical "Behold, I come as a thief" function in verse 15?', 'It is a direct word from Christ inserted into the bowl narrative — echoing His Olivet warning (Matthew 24:43-44) and the Sardis letter (3:3); even amid eschatological judgment, the call to spiritual watchfulness remains urgent and personally addressed', 'It is a scribal insertion', 'It applies only to the past', 'It is spoken by an angel', 'a', 'Revelation 16:15 — "Behold, I come as a thief. Blessed is he that watcheth, and keepeth his garments, lest he walk naked, and they see his shame." This beatitude (the third of seven in Revelation) breaks the narrative to address readers directly — maintaining the pastoral concern amid apocalyptic imagery.'),
('Revelation', 16, 'adults', 6, 'What does the unprecedented earthquake and the splitting of "the great city into three parts" represent?', 'The total collapse of the world system opposed to God — the "great city" (Babylon/world system) disintegrates; islands and mountains vanishing signify the complete dissolution of the present world order in preparation for the new creation', 'A minor seismic event', 'A natural geological shift', 'Rebuilding of the city', 'a', 'Revelation 16:18-20 — "Such as was not since men were upon the earth, so mighty an earthquake, and so great... the great city was divided into three parts... every island fled away, and the mountains were not found." The cosmic scope signals the end of the present order.'),
('Revelation', 16, 'adults', 7, 'What does the persistent refusal to repent (vv.9,11,21) despite escalating plagues reveal?', 'It demonstrates the doctrine of total depravity in extremis — humanity, given every possible warning through catastrophic judgment, blasphemes God rather than repenting; this vindicates divine judgment by showing that greater punishment does not produce genuine repentance apart from sovereign grace', 'Repentance was never offered', 'Some people did repent', 'The plagues were too mild to notice', 'a', 'Revelation 16:9,11,21 — Three explicit statements of refusal: "repented not to give him glory" (v.9), "blasphemed the God of heaven... and repented not" (v.11), "blasphemed God because of the plague of the hail" (v.21). Each plague increases, but so does rebellion.'),
('Revelation', 16, 'adults', 8, 'How does "It is done" (Gegonen) at the seventh bowl parallel Christ''s "It is finished" (Tetelestai)?', 'Both signal completion — Christ''s "It is finished" (John 19:30) completed redemption; the seventh bowl''s "It is done" completes judgment; together they bookend the divine economy: salvation accomplished at the cross, judgment consummated at the bowls', 'There is no parallel', 'They mean different things', 'Only one is important', 'a', 'Revelation 16:17 — "And there came a great voice out of the temple of heaven, from the throne, saying, It is done (Gegonen)." Cf. John 19:30 — "Tetelestai." The cross completed salvation; the bowls complete judgment. Both are definitive, irreversible divine acts.');

-- ═══════════════ CHAPTERS 17–22 ═══════════════

-- ═══ Revelation Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 17, 'kids', 1, 'What did the woman sitting on the scarlet beast look like?', 'She was dressed in purple and scarlet, covered with gold and jewels, and held a golden cup', 'She wore a simple white dress', 'She was dressed in sackcloth', 'She had no special clothing', 'a', 'Revelation 17:4 — "And the woman was arrayed in purple and scarlet colour, and decked with gold and precious stones and pearls, having a golden cup in her hand."'),
('Revelation', 17, 'kids', 2, 'What name was written on the woman''s forehead?', '"Mystery, Babylon the Great, the Mother of Harlots and Abominations of the Earth"', '"Queen of Heaven"', '"Ruler of Nations"', '"Friend of God"', 'a', 'Revelation 17:5 — "And upon her forehead was a name written, MYSTERY, BABYLON THE GREAT, THE MOTHER OF HARLOTS AND ABOMINATIONS OF THE EARTH."'),
('Revelation', 17, 'kids', 3, 'What will happen to Babylon in the end?', 'The beast and the ten horns will hate her, make her desolate, and destroy her with fire', 'She will become more powerful', 'She will be saved', 'Nothing will happen to her', 'a', 'Revelation 17:16 — "And the ten horns which thou sawest upon the beast, these shall hate the whore, and shall make her desolate and naked, and shall eat her flesh, and burn her with fire."'),
-- Teens
('Revelation', 17, 'teens', 1, 'What does the scarlet beast the woman rides on have?', 'Seven heads and ten horns — the heads represent seven mountains and also seven kings', 'Wings and a tail', 'Three heads', 'No distinctive features', 'a', 'Revelation 17:3,9 — "I saw a woman sit upon a scarlet coloured beast, full of names of blasphemy, having seven heads and ten horns... The seven heads are seven mountains, on which the woman sitteth."'),
('Revelation', 17, 'teens', 2, 'What do the waters where the woman sits represent?', 'Peoples, multitudes, nations, and tongues — her influence is worldwide', 'Literal oceans', 'Rivers of paradise', 'Rain from heaven', 'a', 'Revelation 17:15 — "The waters which thou sawest, where the whore sitteth, are peoples, and multitudes, and nations, and tongues."'),
('Revelation', 17, 'teens', 3, 'What do the ten horns represent?', 'Ten kings who have not yet received a kingdom but will receive power with the beast for one hour', 'Ten mountains', 'Ten trumpets', 'Ten cities', 'a', 'Revelation 17:12 — "And the ten horns which thou sawest are ten kings, which have received no kingdom as yet; but receive power as kings one hour with the beast."'),
('Revelation', 17, 'teens', 4, 'Will the beast and the ten kings succeed against the Lamb?', 'No — the Lamb will overcome them because He is Lord of lords and King of kings', 'Yes, the beast will win', 'The battle will never happen', 'They will become allies', 'a', 'Revelation 17:14 — "These shall make war with the Lamb, and the Lamb shall overcome them: for he is Lord of lords, and King of kings: and they that are with him are called, and chosen, and faithful."'),
('Revelation', 17, 'teens', 5, 'Why does God allow the ten kings to serve the beast''s purpose?', 'God put it in their hearts to fulfil His will — even the beast''s allies unknowingly carry out God''s sovereign plan', 'They chose entirely on their own', 'God could not stop them', 'It was a coincidence', 'a', 'Revelation 17:17 — "For God hath put in their hearts to fulfil his will, and to agree, and give their kingdom unto the beast, until the words of God shall be fulfilled."'),
-- Adults
('Revelation', 17, 'adults', 1, 'What does "Babylon the Great" represent in Revelation?', 'A symbolic city representing the world system of idolatry, immorality, and opposition to God — combining the historical echoes of ancient Babylon (Genesis 11; Daniel), Rome (the seven hills, imperial persecution), and every seductive civilisational power that draws humanity from God', 'Only literal ancient Babylon', 'Only the city of Rome', 'A future single city', 'a', 'Revelation 17:5,18 — Babylon functions as a composite symbol. It echoes historical Babylon (anti-God empire), first-century Rome (seven hills — v.9, imperial cult), and every cultural system that seduces humanity through wealth, power, and false religion.'),
('Revelation', 17, 'adults', 2, 'How does the harlot imagery draw on Old Testament prophetic tradition?', 'Israel''s idolatry was consistently portrayed as harlotry (Hosea 1-3; Ezekiel 16; 23; Isaiah 1:21; Jeremiah 3) — the "great whore" combines unfaithfulness to God with seduction of the nations; Babylon-as-harlot corrupts those who should worship God', 'The imagery is original to Revelation', 'It draws from Greek comedy', 'It has no prophetic background', 'a', 'Revelation 17:1-2 — The harlot/prostitute metaphor for false religion and idolatry runs throughout the OT prophets. Ezekiel 16 and 23 are particularly close parallels — unfaithful cities personified as promiscuous women who seduce the nations.'),
('Revelation', 17, 'adults', 3, 'What does the beast that "was, and is not, and yet is" parody?', 'It parodies God''s self-description ("which is, and which was, and which is to come" — 1:4,8) — the beast is a counterfeit deity with a pseudo-resurrection ("deadly wound healed" — 13:3); it "was" (existed), "is not" (received a mortal wound), and "yet is" (returns)', 'It describes a normal life cycle', 'It has no theological significance', 'It is a scribal error', 'a', 'Revelation 17:8 — "The beast that thou sawest was, and is not; and shall ascend out of the bottomless pit, and go into perdition." This deliberately parodies the divine threefold temporal formula, presenting the beast as anti-God with a counterfeit resurrection.'),
('Revelation', 17, 'adults', 4, 'How do the "seven mountains" and "seven kings" function interpretively?', 'They have dual significance: the seven mountains allude to Rome''s seven hills (making the identification recognisable to first-century readers), while the seven kings represent successive forms of anti-God governance throughout history — the number seven suggesting completeness of worldly power', 'They refer only to topography', 'They describe seven individual rulers', 'They have no symbolic meaning', 'a', 'Revelation 17:9-10 — "The seven heads are seven mountains... And there are seven kings." The dual identification (mountains and kings) signals that the symbol operates on multiple levels: geographical (Rome''s hills), political (successive empires), and symbolic (totality of earthly opposition to God).'),
('Revelation', 17, 'adults', 5, 'What is the theological significance of Babylon being destroyed by the beast she rides?', 'The world system of false religion is ultimately consumed by the political-military power it rode — evil is self-destructive; the coalition of wickedness turns on itself because sin cannot sustain unity; and God sovereignly uses evil to judge evil', 'Babylon destroys the beast instead', 'They remain allies', 'The destruction is accidental', 'a', 'Revelation 17:16-17 — "The ten horns... shall hate the whore, and shall make her desolate... For God hath put in their hearts to fulfil his will." The false religious system is destroyed by the very political power it exploited. God''s sovereignty operates even through the self-destructive nature of evil alliances.'),
('Revelation', 17, 'adults', 6, 'What does "the Lamb shall overcome them: for he is Lord of lords, and King of kings" establish christologically?', 'Christ holds the supreme title that transcends all earthly sovereignty — the double superlative "Lord of lords and King of kings" (cf. Deuteronomy 10:17; Daniel 2:47; 1 Timothy 6:15) asserts absolute, unchallengeable authority over every ruler and power', 'The Lamb is one king among many', 'The title is honorary only', 'Other lords share equal authority', 'a', 'Revelation 17:14 — The title "Lord of lords and King of kings" (reversed in 19:16 as "KING OF KINGS, AND LORD OF LORDS") is the supreme sovereignty title. No coalition of earthly or demonic power can challenge the Lamb''s absolute authority.'),
('Revelation', 17, 'adults', 7, 'How does the angel''s statement "the woman which thou sawest is that great city, which reigneth over the kings of the earth" function?', 'It provides the interpretive key — the woman symbolises a dominant civilisational power that exercises cultural, economic, and religious hegemony over the world''s rulers; in John''s day this was Rome, but the symbol transcends any single historical identification', 'It identifies a single modern city', 'It refers to Jerusalem only', 'It has no clear referent', 'a', 'Revelation 17:18 — "The woman which thou sawest is that great city, which reigneth over the kings of the earth." For first-century readers, this unmistakably pointed to Rome. But the symbol''s composite nature (Babylon''s name, Rome''s hills, universal scope) transcends any single identification.'),
('Revelation', 17, 'adults', 8, 'What does "God hath put in their hearts to fulfil his will" reveal about divine sovereignty and human evil?', 'God''s sovereignty operates even through the wicked — the ten kings act from their own evil motives (hatred of the harlot), yet unknowingly execute God''s predetermined plan; divine sovereignty and human agency operate simultaneously without contradiction', 'God forces them against their will', 'God is uninvolved in their actions', 'Their actions surprise God', 'a', 'Revelation 17:17 — "For God hath put in their hearts to fulfil his will." This is a profound statement of compatibilist sovereignty: the kings act freely from evil motives, yet God has directed their hearts toward His purpose (cf. Proverbs 21:1). Divine sovereignty does not negate human agency.');

-- ═══ Revelation Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 18, 'kids', 1, 'What did the angel announce about Babylon?', '"Babylon the great is fallen, is fallen" — she has been completely destroyed', 'Babylon will be rebuilt', 'Babylon is still standing', 'Babylon became a good city', 'a', 'Revelation 18:2 — "And he cried mightily with a strong voice, saying, Babylon the great is fallen, is fallen."'),
('Revelation', 18, 'kids', 2, 'What did God tell His people to do?', '"Come out of her, my people, that ye be not partakers of her sins"', '"Stay and fight"', '"Hide inside the city"', '"Rebuild the walls"', 'a', 'Revelation 18:4 — "And I heard another voice from heaven, saying, Come out of her, my people, that ye be not partakers of her sins, and that ye receive not of her plagues."'),
('Revelation', 18, 'kids', 3, 'Who was sad when Babylon fell?', 'The merchants and kings of the earth who got rich from her — they cried and mourned', 'The angels in heaven', 'God''s people', 'The animals of the earth', 'a', 'Revelation 18:9,11 — "And the kings of the earth, who have committed fornication and lived deliciously with her, shall bewail her... And the merchants of the earth shall weep and mourn over her."'),
-- Teens
('Revelation', 18, 'teens', 1, 'Why did God judge Babylon?', 'Because her sins reached unto heaven and God remembered her iniquities — she glorified herself and lived deliciously while persecuting the saints', 'Because she was too small', 'Because she charged too much for food', 'Because her buildings were ugly', 'a', 'Revelation 18:5,7 — "For her sins have reached unto heaven, and God hath remembered her iniquities... How much she hath glorified herself, and lived deliciously."'),
('Revelation', 18, 'teens', 2, 'How quickly was Babylon destroyed?', '"In one hour" — her judgment came suddenly and completely', 'Over many years', 'Gradually over centuries', 'It took a full decade', 'a', 'Revelation 18:10 — "Alas, alas that great city Babylon, that mighty city! for in one hour is thy judgment come."'),
('Revelation', 18, 'teens', 3, 'What did the merchants trade that included human beings?', 'A long list including gold, silver, precious stones, fine fabrics, spices, animals, and "slaves, and souls of men"', 'Only food and water', 'Only building materials', 'Only animals', 'a', 'Revelation 18:12-13 — "The merchandise of gold, and silver, and precious stones... and slaves, and souls of men."'),
('Revelation', 18, 'teens', 4, 'How is heaven told to respond to Babylon''s fall?', '"Rejoice over her, thou heaven, and ye holy apostles and prophets; for God hath avenged you on her"', '"Mourn for her loss"', '"Rebuild her quickly"', '"Ignore what happened"', 'a', 'Revelation 18:20 — "Rejoice over her, thou heaven, and ye holy apostles and prophets; for God hath avenged you on her."'),
('Revelation', 18, 'teens', 5, 'What dramatic action did a mighty angel perform?', 'He took up a stone like a great millstone and cast it into the sea, saying "Thus with violence shall that great city Babylon be thrown down"', 'He blew a trumpet', 'He poured out a vial', 'He opened a scroll', 'a', 'Revelation 18:21 — "And a mighty angel took up a stone like a great millstone, and cast it into the sea, saying, Thus with violence shall that great city Babylon be thrown down, and shall be found no more at all."'),
-- Adults
('Revelation', 18, 'adults', 1, 'How does the "Come out of her, my people" command echo Old Testament exodus theology?', 'It echoes Isaiah 48:20 ("Go ye forth of Babylon"), Jeremiah 50:8 ("Remove out of the midst of Babylon"), and Jeremiah 51:6,45 ("Flee out of the midst of Babylon") — the call to separate from the corrupt world system is a new exodus, a definitive break from spiritual captivity', 'It is a new command with no precedent', 'It echoes Greek philosophy', 'It applies only to first-century Christians', 'a', 'Revelation 18:4 — "Come out of her, my people." The imperative echoes the prophetic call to flee Babylon (Isaiah 48:20; Jeremiah 50:8; 51:6,45; cf. 2 Corinthians 6:17). Separation from Babylon is both spiritual (rejecting her values) and potentially physical (withdrawing from her systems).'),
('Revelation', 18, 'adults', 2, 'How does the threefold lament of kings, merchants, and sailors function literarily?', 'It echoes Ezekiel 26-27''s lament over Tyre — three groups who profited from the city mourn its fall: kings (political allies), merchants (economic partners), and sailors (trade facilitators); each group mourns not Babylon herself but their own lost profit', 'The laments are spontaneous and unstructured', 'Only one group mourns', 'They mourn from genuine love', 'a', 'Revelation 18:9-19 — The three laments parallel Ezekiel 27''s structure (Tyre''s trading partners). Crucially, each group mourns at a distance ("standing afar off" — vv.10,15,17), afraid of sharing her fate. Their grief is self-interested, not compassionate.'),
('Revelation', 18, 'adults', 3, 'What does the inclusion of "slaves, and souls of men" at the end of the cargo list reveal?', 'The climactic position of human trafficking exposes Babylon''s ultimate evil — the world system that trades in luxury goods ultimately commodifies human beings; the progression from material goods to human souls unmasks the dehumanising logic of exploitative economics', 'It is a random item in the list', 'Slavery was insignificant to John', 'It is a scribal addition', 'a', 'Revelation 18:13 — "Slaves (sōmatōn), and souls of men (psychas anthrōpōn)." The Greek literally reads "bodies and souls of men" — distinguishing physical enslavement (bodies) from spiritual exploitation (souls). Babylon''s commerce ultimately trades in humanity itself.'),
('Revelation', 18, 'adults', 4, 'How does the millstone imagery in verse 21 draw on Jeremiah 51?', 'Jeremiah 51:63-64 commands that a stone be tied to a scroll and thrown into the Euphrates as Babylon sinks — Revelation reuses the prophetic action with a millstone (cf. Jesus'' millstone warning in Matthew 18:6), signifying Babylon''s violent, permanent, and irrecoverable destruction', 'The millstone is original to Revelation', 'It echoes only Greek myths', 'Jeremiah describes a different city', 'a', 'Revelation 18:21 — "A stone like a great millstone, and cast it into the sea." Cf. Jeremiah 51:63-64 — "Bind a stone to it, and cast it into the midst of Euphrates: And thou shalt say, Thus shall Babylon sink, and shall not rise." The prophetic action is dramatically intensified.'),
('Revelation', 18, 'adults', 5, 'What does the sevenfold "no more" in verses 21-23 signify?', 'The complete, irreversible cessation of all civilisational activity — music, craftsmanship, food production, lighting, and marriage; seven "no more" (ou mē... eti) statements represent the total extinction of human culture in Babylon', 'A temporary pause', 'Only one activity ceases', 'Civilisation continues elsewhere', 'a', 'Revelation 18:21-23 — Seven "no more" declarations: (1) musicians, (2) craftsmen, (3) millstones, (4) light, (5) bridegroom/bride voices, (6) merchants, (7) sorcery. The comprehensive list eliminates every dimension of civilised life — Babylon is rendered permanently uninhabitable.'),
('Revelation', 18, 'adults', 6, 'What does "in her was found the blood of prophets, and of saints, and of all that were slain upon the earth" attribute to Babylon?', 'Babylon bears corporate guilt for all persecution of God''s people throughout history — she is the spiritual mother of all anti-God violence from Abel onward (cf. Matthew 23:35); the world system that opposes God is ultimately responsible for all martyrdom', 'Only specific historical murders', 'Only first-century persecution', 'She is innocent of bloodshed', 'a', 'Revelation 18:24 — "And in her was found the blood of prophets, and of saints, and of all that were slain upon the earth." Cf. Matthew 23:35; Luke 11:50-51. Babylon is the spiritual fountainhead of all opposition to God, accountable for the cumulative blood guilt of history.'),
('Revelation', 18, 'adults', 7, 'How does heaven''s joy (18:20) relate to the saints'' prayer in 6:10?', 'The martyrs'' cry "How long, O Lord?" receives its answer — God has avenged their blood; heaven''s rejoicing is not sadistic but judicial vindication; the long-suffering prayer of the persecuted is finally and fully answered in Babylon''s fall', 'The two passages are unrelated', 'The prayer was forgotten', 'Heaven mourns rather than rejoices', 'a', 'Revelation 18:20 — "God hath avenged you on her." This answers 6:10 — "How long, O Lord, holy and true, dost thou not judge and avenge our blood?" The narrative arc from prayer (6:10) through patience (13:10; 14:12) to vindication (18:20) is now complete.'),
('Revelation', 18, 'adults', 8, 'How does chapter 18 function as an anti-epithalamium (inverted wedding song)?', 'The chapter systematically eliminates every element of celebration — music (v.22), feasting (v.22), light (v.23), and the bridegroom''s voice (v.23) — the very elements of a wedding feast; this prepares for the true wedding feast of the Lamb in 19:7-9', 'The chapter celebrates a wedding', 'There is no wedding imagery', 'The imagery is coincidental', 'a', 'Revelation 18:22-23 removes the elements of joyful celebration, especially "the voice of the bridegroom and of the bride" (cf. Jeremiah 7:34; 16:9; 25:10). Babylon''s silenced wedding prepares for the Lamb''s true wedding in the very next chapter.');

-- ═══ Revelation Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 19, 'kids', 1, 'What did the great multitude in heaven shout?', '"Alleluia; Salvation, and glory, and honour, and power, unto the Lord our God"', '"We are tired"', '"Send us home"', '"Give us more food"', 'a', 'Revelation 19:1 — "And after these things I heard a great voice of much people in heaven, saying, Alleluia; Salvation, and glory, and honour, and power, unto the Lord our God."'),
('Revelation', 19, 'kids', 2, 'What special celebration is announced in heaven?', 'The marriage supper of the Lamb — Jesus is the groom and His people are the bride', 'A birthday party', 'A harvest festival', 'A new year celebration', 'a', 'Revelation 19:7,9 — "The marriage of the Lamb is come, and his wife hath made herself ready... Blessed are they which are called unto the marriage supper of the Lamb."'),
('Revelation', 19, 'kids', 3, 'What name is written on the rider of the white horse?', '"King of Kings, and Lord of Lords"', '"Strongest Warrior"', '"Greatest General"', '"Mightiest Hero"', 'a', 'Revelation 19:16 — "And he hath on his vesture and on his thigh a name written, KING OF KINGS, AND LORD OF LORDS."'),
-- Teens
('Revelation', 19, 'teens', 1, 'What is the bride of the Lamb wearing?', 'Fine linen, clean and white — the fine linen represents the righteous acts of the saints', 'A golden dress', 'Purple and scarlet like Babylon', 'Ordinary everyday clothes', 'a', 'Revelation 19:8 — "And to her was granted that she should be arrayed in fine linen, clean and white: for the fine linen is the righteousness of saints."'),
('Revelation', 19, 'teens', 2, 'How is the rider on the white horse described?', 'His eyes are as a flame of fire, He has many crowns, His name is "The Word of God," and His vesture is dipped in blood', 'He is riding a chariot', 'He wears simple robes', 'He has no distinguishing marks', 'a', 'Revelation 19:12-13 — "His eyes were as a flame of fire, and on his head were many crowns... he was clothed with a vesture dipped in blood: and his name is called The Word of God."'),
('Revelation', 19, 'teens', 3, 'What weapon does the rider use to smite the nations?', 'A sharp sword that goes out of His mouth — He rules with a rod of iron', 'A bow and arrows', 'A spear', 'A battle axe', 'a', 'Revelation 19:15 — "And out of his mouth goeth a sharp sword, that with it he should smite the nations: and he shall rule them with a rod of iron."'),
('Revelation', 19, 'teens', 4, 'What happened to the beast and the false prophet?', 'They were both cast alive into a lake of fire burning with brimstone', 'They escaped and hid', 'They surrendered peacefully', 'They were forgiven', 'a', 'Revelation 19:20 — "And the beast was taken, and with him the false prophet... These both were cast alive into a lake of fire burning with brimstone."'),
('Revelation', 19, 'teens', 5, 'What are the four "Alleluias" in this chapter about?', 'Praising God for His righteous judgment of Babylon (vv.1-2), the finality of her destruction (v.3), worship of God on His throne (v.4), and the reign of the Lord God omnipotent (v.6)', 'Celebrating a military parade', 'Mourning the loss of Babylon', 'Welcoming a new prophet', 'a', 'Revelation 19:1,3,4,6 — The fourfold "Alleluia" (the only occurrences in the NT) celebrates God''s just judgment (vv.1-2), its permanence (v.3), divine enthronement (v.4), and God''s omnipotent reign (v.6).'),
-- Adults
('Revelation', 19, 'adults', 1, 'What is the significance of "Alleluia" appearing four times — the only occurrences in the New Testament?', '"Alleluia" (Hallelu-Yah — "Praise the LORD") from the Psalms (Psalm 104:35; 106:1; 111-113; 135; 146-150) now appears in its ultimate eschatological context — the final vindication of God''s justice evokes the Psalter''s greatest praise vocabulary in its definitive, cosmic expression', 'The word is coincidental', 'It appears elsewhere in the NT', 'It is a Greek word', 'a', 'Revelation 19:1,3,4,6 — "Alleluia" is transliterated Hebrew (הַלְלוּ יָהּ) used only here in the NT. Its fourfold occurrence (four = universal, earthly completeness) brings the Psalter''s praise to its eschatological culmination — the ultimate reason for "Hallelu-Yah" is God''s final righteous judgment.'),
('Revelation', 19, 'adults', 2, 'How does the marriage of the Lamb fulfil Old Testament covenant imagery?', 'The OT consistently portrays God''s relationship with Israel as a marriage (Hosea 2:19-20; Isaiah 54:5; 62:4-5; Ezekiel 16:8-14) — the Lamb''s marriage is the consummation of the covenant relationship: the bride has "made herself ready" through faithful obedience, clothed in the righteous acts of the saints', 'Marriage imagery is new in Revelation', 'It applies only to individuals', 'It has no covenant significance', 'a', 'Revelation 19:7-8 — The marriage metaphor consummates the OT imagery: Hosea''s restored marriage (2:19-20), Isaiah''s rejoicing bridegroom (62:5), the Song of Solomon''s love. The bride''s readiness shows the church''s cooperative response to grace.'),
('Revelation', 19, 'adults', 3, 'What does the title "The Word of God" (ho Logos tou Theou) connect to?', 'John 1:1 — "In the beginning was the Word" — the same Johannine christological title identifying the rider as the pre-existent, incarnate, and now glorified Christ; the creative and revelatory Word is also the judging Word', 'It refers to the Bible itself', 'It is a new title with no background', 'It applies to an angel', 'a', 'Revelation 19:13 — "His name is called The Word of God." The Johannine logos theology (John 1:1,14; 1 John 1:1) identifies this rider as the same Word who was "in the beginning with God" — now manifested as the divine warrior executing final judgment.'),
('Revelation', 19, 'adults', 4, 'What does the "vesture dipped in blood" signify?', 'It echoes Isaiah 63:1-3 — the divine warrior from Edom with garments stained from treading the winepress of judgment; the blood is that of His enemies (anticipated judgment), not His own sacrificial blood — though the dual reference enriches the imagery', 'It is Christ''s own blood only', 'It refers to a laundry accident', 'The blood has no significance', 'a', 'Revelation 19:13 — "Clothed with a vesture dipped in blood." Isaiah 63:2-3 — "Wherefore art thou red in thine apparel?... I have trodden the winepress alone... their blood shall be sprinkled upon my garments." The primary allusion is to judgment, not atonement.'),
('Revelation', 19, 'adults', 5, 'How does Christ''s sole weapon being the sword from His mouth redefine conquest?', 'Christ conquers entirely by His word — no physical army, no conventional weapons; the spoken word of God is sufficient to defeat all opposition; this reinterprets divine warfare as the omnipotent efficacy of Christ''s authoritative speech', 'He also uses conventional weapons', 'The sword is decorative', 'His army does the fighting', 'a', 'Revelation 19:15,21 — "Out of his mouth goeth a sharp sword, that with it he should smite the nations... the remnant were slain with the sword of him that sat upon the horse, which sword proceeded out of his mouth." Christ''s word alone — creative, judicial, irresistible — is His only weapon.'),
('Revelation', 19, 'adults', 6, 'What is the theological significance of the beast and false prophet being the first occupants of the lake of fire?', 'They precede even Satan (who joins them in 20:10) — the anti-trinity''s two earthly agents are judged before their master; their being cast "alive" emphasises conscious, ongoing judgment; the lake of fire becomes the final destiny of everything opposed to God', 'They are annihilated instantly', 'They escape later', 'Only Satan enters the lake of fire', 'a', 'Revelation 19:20 — "Cast alive into a lake of fire." The beast and false prophet are the first to enter (still there in 20:10 — "where the beast and the false prophet are"), establishing the lake of fire as a place of conscious, eternal punishment for God''s enemies.'),
('Revelation', 19, 'adults', 7, 'What does the angel''s rebuke "worship God" when John falls at his feet reveal?', 'Even in the overwhelming context of heavenly glory, worship belongs to God alone — the angel identifies himself as a "fellowservant" of John and the prophets; this anti-worship reflex (repeated in 22:8-9) reinforces monotheistic worship as Revelation''s central ethical demand', 'Angels deserve worship', 'John was wrong to worship at all', 'Worship is unimportant in Revelation', 'a', 'Revelation 19:10 — "See thou do it not: I am thy fellowservant... worship God." This correction (repeated in 22:8-9) underscores Revelation''s central message: worship God alone. Even the most glorious heavenly being refuses worship — only God and the Lamb receive it.'),
('Revelation', 19, 'adults', 8, 'How does "the testimony of Jesus is the spirit of prophecy" define the relationship between testimony and prophecy?', 'All true prophecy centres on and testifies to Jesus — the Holy Spirit''s prophetic activity is fundamentally christocentric; every genuine prophetic word, whether in Scripture or the church, has Jesus as its essential content and goal', 'Prophecy has nothing to do with Jesus', 'Testimony replaces prophecy', 'The statement is unclear', 'a', 'Revelation 19:10 — "The testimony of Jesus is the spirit of prophecy." This programmatic statement means that the animating purpose (spirit/pneuma) of all prophecy is testimony about Jesus. Christ is not just one prophetic topic among many — He is the sum and substance of all prophetic revelation.');

-- ═══ Revelation Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 20, 'kids', 1, 'What happened to Satan for a thousand years?', 'An angel bound him with a great chain and locked him in the bottomless pit for a thousand years', 'He was set free', 'He became good', 'Nothing happened to him', 'a', 'Revelation 20:1-3 — "And he laid hold on the dragon, that old serpent, which is the Devil, and Satan, and bound him a thousand years, And cast him into the bottomless pit, and shut him up."'),
('Revelation', 20, 'kids', 2, 'What happens at the great white throne judgment?', 'Everyone is judged according to their works, and the books are opened including the book of life', 'Everyone receives a reward', 'No one is judged', 'Only kings are judged', 'a', 'Revelation 20:12 — "And I saw the dead, small and great, stand before God; and the books were opened: and another book was opened, which is the book of life: and the dead were judged out of those things which were written in the books, according to their works."'),
('Revelation', 20, 'kids', 3, 'What is the last enemy that is thrown into the lake of fire?', 'Death and hell (hades) — they are completely destroyed', 'An army', 'A dragon', 'A mountain', 'a', 'Revelation 20:14 — "And death and hell were cast into the lake of fire. This is the second death."'),
-- Teens
('Revelation', 20, 'teens', 1, 'What happened after Satan was released from the thousand years?', 'He went out to deceive the nations (Gog and Magog) to gather them for battle, but fire from heaven devoured them', 'He repented and became good', 'He disappeared forever', 'He made peace with God', 'a', 'Revelation 20:7-9 — "And when the thousand years are expired, Satan shall be loosed out of his prison, And shall go out to deceive the nations... Gog, and Magog, to gather them together to battle... And fire came down from God out of heaven, and devoured them."'),
('Revelation', 20, 'teens', 2, 'Where was Satan finally thrown?', 'Into the lake of fire and brimstone where the beast and false prophet are, to be tormented day and night for ever and ever', 'Into a deep cave', 'Into the ocean', 'Back into the bottomless pit', 'a', 'Revelation 20:10 — "And the devil that deceived them was cast into the lake of fire and brimstone, where the beast and the false prophet are, and shall be tormented day and night for ever and ever."'),
('Revelation', 20, 'teens', 3, 'Who sat on the thrones during the thousand years?', 'Those who had been beheaded for Jesus'' testimony and God''s word, who had not worshipped the beast — they lived and reigned with Christ', 'The kings of the earth', 'The beast and false prophet', 'Nobody sat on thrones', 'a', 'Revelation 20:4 — "And I saw thrones, and they sat upon them, and judgment was given unto them: and I saw the souls of them that were beheaded for the witness of Jesus, and for the word of God, and which had not worshipped the beast... and they lived and reigned with Christ a thousand years."'),
('Revelation', 20, 'teens', 4, 'What is the second death?', 'The lake of fire — anyone whose name was not found in the book of life was cast into it', 'Physical death', 'Falling asleep', 'Losing your home', 'a', 'Revelation 20:14-15 — "And death and hell were cast into the lake of fire. This is the second death. And whosoever was not found written in the book of life was cast into the lake of fire."'),
('Revelation', 20, 'teens', 5, 'What is the "first resurrection"?', 'The resurrection of those who reign with Christ during the thousand years — "Blessed and holy is he that hath part in the first resurrection: on such the second death hath no power"', 'The resurrection of all people at once', 'Being born again physically', 'Waking up in the morning', 'a', 'Revelation 20:5-6 — "This is the first resurrection. Blessed and holy is he that hath part in the first resurrection: on such the second death hath no power, but they shall be priests of God and of Christ, and shall reign with him a thousand years."'),
-- Adults
('Revelation', 20, 'adults', 1, 'What are the major interpretive positions on the millennium?', 'Premillennialism (Christ returns before a literal 1,000-year reign), amillennialism (the 1,000 years symbolise the present church age with Christ reigning in heaven), and postmillennialism (Christ returns after the church progressively Christianises the world) — each has substantial exegetical support', 'There is only one valid interpretation', 'The millennium is not mentioned in Revelation', 'All scholars agree on the meaning', 'a', 'Revelation 20:1-6 — The three main positions reflect different hermeneutical approaches to apocalyptic numbers and the sequence of events. Premillennialism reads the text sequentially; amillennialism sees recapitulation; postmillennialism emphasises kingdom growth.'),
('Revelation', 20, 'adults', 2, 'How does "Gog and Magog" connect to Ezekiel 38-39?', 'Ezekiel 38-39 describes a future invasion of restored Israel by Gog from the land of Magog — Revelation universalises this: Gog and Magog become symbols for all nations gathered against God''s people in the final rebellion, transcending the original geographical reference', 'There is no connection to Ezekiel', 'Gog and Magog are cities', 'They are historical kings only', 'a', 'Revelation 20:8 — "Gog and Magog, to gather them together to battle: the number of whom is as the sand of the sea." John takes Ezekiel''s specific northern enemy and universalises it — Gog and Magog become a comprehensive symbol for anti-God humanity.'),
('Revelation', 20, 'adults', 3, 'What does the great white throne judgment reveal about final accountability?', 'Universal, comprehensive judgment — "the dead, small and great" stand before God; the "books" record works (basis of judgment), while the "book of life" determines destiny; the judgment is both according to works (evaluative) and according to the book of life (salvific)', 'Only evil people are judged', 'Judgment is random', 'Works are irrelevant', 'a', 'Revelation 20:12-13 — "The dead were judged out of those things which were written in the books, according to their works." Two sets of records: books of works (what people did) and the book of life (whose names are inscribed). Both are consulted — works demonstrate faith''s reality; the book of life secures destiny.'),
('Revelation', 20, 'adults', 4, 'What does the casting of death and Hades into the lake of fire signify?', 'The permanent abolition of death itself — the last enemy (1 Corinthians 15:26) is destroyed; death and its realm (Hades) are personified and judged, meaning mortality and the intermediate state are terminated; from this point, only eternal life and the second death exist', 'Death continues in a different form', 'Hades is relocated', 'Only physical death ends', 'a', 'Revelation 20:14 — "Death and hell were cast into the lake of fire." 1 Corinthians 15:26 — "The last enemy that shall be destroyed is death." Death itself dies — the ultimate consequence of sin (Romans 6:23) is itself consumed, making the new creation truly deathless (21:4).'),
('Revelation', 20, 'adults', 5, 'How does "the second death hath no power" over first-resurrection participants function?', 'Those who share in the first resurrection (whether physical or spiritual, depending on millennial view) are permanently immune from the lake of fire — they are "priests of God and of Christ," combining Exodus 19:6''s royal-priestly vocation with eternal security', 'The second death has power over everyone', 'The promise is conditional', 'It applies only temporarily', 'a', 'Revelation 20:6 — "Blessed and holy is he that hath part in the first resurrection: on such the second death hath no power." This is the fifth of Revelation''s seven beatitudes, guaranteeing eternal security for those who belong to Christ.'),
('Revelation', 20, 'adults', 6, 'What does Satan''s release and final rebellion demonstrate?', 'That a thousand years of bondage does not reform evil — Satan immediately resumes deception; and that human nature, even after prolonged peace, is susceptible to rebellion apart from grace; the final revolt demonstrates the inexhaustibility of evil and the necessity of its permanent removal', 'Satan was reformed during imprisonment', 'The millennium made everyone righteous', 'Evil no longer exists after the binding', 'a', 'Revelation 20:7-8 — Satan''s immediate resumption of deception after a thousand years proves that restraint does not equal transformation. The brief final rebellion serves to demonstrate conclusively the incorrigible nature of evil before its eternal sentence.'),
('Revelation', 20, 'adults', 7, 'How does fire from heaven consuming the final rebellion echo Ezekiel 38-39?', 'Ezekiel 39:6 — "I will send a fire on Magog" — God''s direct intervention by fire from heaven destroys the armies surrounding "the camp of the saints and the beloved city" without any human military action; divine judgment is immediate, total, and sovereign', 'There is no fire in Ezekiel', 'The church fights the battle', 'Nuclear weapons are implied', 'a', 'Revelation 20:9 — "Fire came down from God out of heaven, and devoured them." cf. Ezekiel 38:22; 39:6 — fire and brimstone on Gog. The pattern of divine intervention by fire (cf. Genesis 19:24 — Sodom; 2 Kings 1:10 — Elijah) shows God alone executes the final victory.'),
('Revelation', 20, 'adults', 8, 'What does "tormented day and night for ever and ever" establish about the nature of final judgment?', 'It describes conscious, eternal punishment — the language "day and night" (continuous) and "for ever and ever" (eis tous aiōnas tōn aiōnōn — unto the ages of the ages) is the strongest possible expression of unending duration in Greek, the same phrase used for God''s own eternal existence (4:9-10)', 'Punishment is temporary', 'The language is merely metaphorical', 'Annihilation is implied', 'a', 'Revelation 20:10 — "Tormented day and night for ever and ever." The phrase eis tous aiōnas tōn aiōnōn is used of God''s eternal life (4:9-10; 10:6; 15:7), the Lamb''s worship (5:13), and now the punishment of the devil, beast, and false prophet — same duration in every case.');

-- ═══ Revelation Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 21, 'kids', 1, 'What did John see coming down from heaven?', 'A new Jerusalem — a beautiful holy city prepared as a bride adorned for her husband', 'A new garden', 'A cloud of stars', 'A golden chariot', 'a', 'Revelation 21:2 — "And I John saw the holy city, new Jerusalem, coming down from God out of heaven, prepared as a bride adorned for her husband."'),
('Revelation', 21, 'kids', 2, 'What will God wipe away?', 'All tears from their eyes — there will be no more death, sorrow, crying, or pain', 'Dirt from their hands', 'Snow from their clothes', 'Sand from their feet', 'a', 'Revelation 21:4 — "And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away."'),
('Revelation', 21, 'kids', 3, 'What were the twelve gates of the new city made of?', 'Each gate was a single pearl — the gates of pearl', 'Wooden planks', 'Iron bars', 'Stone blocks', 'a', 'Revelation 21:21 — "And the twelve gates were twelve pearls: every several gate was of one pearl."'),
-- Teens
('Revelation', 21, 'teens', 1, 'What declaration does God make from His throne?', '"Behold, I make all things new" — everything is being made fresh and perfect', '"I am tired of creating"', '"Everything stays the same"', '"I will destroy all things"', 'a', 'Revelation 21:5 — "And he that sat upon the throne said, Behold, I make all things new."'),
('Revelation', 21, 'teens', 2, 'What is notably absent from the new Jerusalem?', 'There is no temple — because the Lord God Almighty and the Lamb are the temple', 'There are no people', 'There is no light', 'There is no ground', 'a', 'Revelation 21:22 — "And I saw no temple therein: for the Lord God Almighty and the Lamb are the temple of it."'),
('Revelation', 21, 'teens', 3, 'What provides light in the new Jerusalem?', 'The glory of God and the Lamb — there is no need for the sun or moon', 'Electric lights', 'Candles and torches', 'The moon and stars only', 'a', 'Revelation 21:23 — "And the city had no need of the sun, neither of the moon, to shine in it: for the glory of God did lighten it, and the Lamb is the light thereof."'),
('Revelation', 21, 'teens', 4, 'What are the foundations of the city walls decorated with?', 'Twelve precious stones — jasper, sapphire, chalcedony, emerald, sardonyx, sardius, chrysolyte, beryl, topaz, chrysoprasus, jacinth, and amethyst', 'Plain grey stone', 'Wooden beams', 'Bricks of clay', 'a', 'Revelation 21:19-20 — "And the foundations of the wall of the city were garnished with all manner of precious stones."'),
('Revelation', 21, 'teens', 5, 'Who will NOT enter the new Jerusalem?', 'Nothing that defiles, works abomination, or makes a lie — only those written in the Lamb''s book of life', 'Only wealthy people', 'Only certain nations', 'Everyone without exception', 'a', 'Revelation 21:27 — "And there shall in no wise enter into it any thing that defileth, neither whatsoever worketh abomination, or maketh a lie: but they which are written in the Lamb''s book of life."'),
-- Adults
('Revelation', 21, 'adults', 1, 'How does "a new heaven and a new earth" fulfil Isaiah 65:17 and 66:22?', 'Isaiah prophesied God creating "new heavens and a new earth" — Revelation shows the fulfilment: not merely renovation but transformation; "the first heaven and the first earth were passed away" indicates the radical newness of the eschatological order while maintaining continuity with creation''s original purpose', 'There is no Isaiah connection', 'Only the earth is renewed', 'Isaiah describes a different event', 'a', 'Revelation 21:1 — "I saw a new heaven and a new earth: for the first heaven and the first earth were passed away." Isaiah 65:17 — "For, behold, I create new heavens and a new earth." The Greek kainos means qualitatively new (not neos — chronologically new) — renewed and perfected rather than replaced.'),
('Revelation', 21, 'adults', 2, 'What does "the sea was no more" signify?', 'The sea in Revelation symbolises chaos, the source of the beast (13:1), and separation from God — its abolition signifies the end of all chaotic, threatening, and separating forces; the primordial chaos is finally and permanently subdued', 'Literal oceans are destroyed', 'Fish are extinct', 'Sailing becomes impossible', 'a', 'Revelation 21:1 — "And there was no more sea." In the ancient Near Eastern worldview and in Revelation specifically, the sea represents chaos (Isaiah 57:20), the abyss (Revelation 11:7; 13:1), and danger. Its removal means all forces of chaos, evil, and separation are permanently eliminated.'),
('Revelation', 21, 'adults', 3, 'How does "the tabernacle of God is with men" fulfil the entire biblical narrative?', 'It consummates the trajectory from Eden (God walking with Adam), through the tabernacle (Exodus 25:8 — "that I may dwell among them"), the temple, the incarnation (John 1:14 — "tabernacled among us"), to the eternal dwelling — the goal of all redemptive history is achieved: unmediated divine-human communion', 'It describes a physical tent', 'God has always dwelt with humanity', 'This is a temporary arrangement', 'a', 'Revelation 21:3 — "Behold, the tabernacle of God is with men, and he will dwell with them, and they shall be his people, and God himself shall be with them, and be their God." This is the Bible''s final answer to its opening question: God and humanity together.'),
('Revelation', 21, 'adults', 4, 'What does the city''s cubic shape (equal length, breadth, and height) signify?', 'The Holy of Holies in Solomon''s temple was a perfect cube (1 Kings 6:20 — 20 cubits each dimension) — the entire new Jerusalem is a Holy of Holies, meaning every part of the city is the most sacred space; all God''s people live in His immediate, unmediated presence', 'The shape is random', 'It is an architectural preference', 'Cubes were common in ancient cities', 'a', 'Revelation 21:16 — "The length and the breadth and the height of it are equal." The only perfect cube in Scripture is the Holy of Holies (1 Kings 6:20). The entire city IS the Holy of Holies — the entire new creation is God''s immediate dwelling place.'),
('Revelation', 21, 'adults', 5, 'How do the twelve gates and twelve foundations connect Israel and the church?', 'The twelve gates bear the names of the twelve tribes of Israel, and the twelve foundations bear the names of the twelve apostles — the city unites God''s people from both testaments into one eschatological community; there are not two separate peoples but one redeemed humanity', 'Israel and the church are separate cities', 'Only the apostles are represented', 'Only Israel is represented', 'a', 'Revelation 21:12-14 — Gates = twelve tribes of Israel (entry); foundations = twelve apostles (basis). The city''s structure integrates Old and New Testament people of God into one unified community — the patriarchs are the entry points, the apostles are the foundation.'),
('Revelation', 21, 'adults', 6, 'What does the absence of a temple signify?', 'No mediating structure is needed because "the Lord God Almighty and the Lamb are the temple" — the entire city is a temple (cube-shaped Holy of Holies); the temple''s function (enabling divine-human encounter) is universalised; the symbol is transcended by the reality', 'The city has rejected religion', 'Temples were unpopular', 'A temple will be built later', 'a', 'Revelation 21:22 — "I saw no temple therein: for the Lord God Almighty and the Lamb are the temple of it." Throughout Scripture, temples facilitated meeting God. Now God''s presence is so pervasive that no sacred-secular distinction exists — everywhere is the Holy of Holies.'),
('Revelation', 21, 'adults', 7, 'How does "the nations of them which are saved shall walk in the light of it" envision the new creation?', 'It fulfils Isaiah 60:3,11 (nations walking in Zion''s light, gates never shut) — the new Jerusalem draws the nations into God''s glory; diversity ("nations") is preserved in eternity; ethnic and cultural richness is not abolished but redeemed and brought into God''s light', 'All national distinctions vanish', 'Only one nation survives', 'The nations are punished', 'a', 'Revelation 21:24,26 — "The nations of them which are saved shall walk in the light of it: and the kings of the earth do bring their glory and honour into it... And they shall bring the glory and honour of the nations into it." Cultural diversity is eternally preserved and consecrated.'),
('Revelation', 21, 'adults', 8, 'What does "Behold, I make all things new" reveal about the nature of the new creation?', 'God does not make "all new things" but makes "all things new" — transformation, not replacement; continuity with the original creation is maintained but everything is renewed and perfected; the material world is redeemed, not discarded, fulfilling Romans 8:19-22''s hope of creation''s liberation', 'Creation is annihilated and replaced', 'Only spiritual realities are renewed', 'The material world is evil', 'a', 'Revelation 21:5 — "Behold, I make all things new (kaina)." The word order is significant: not "new things" but "all things new." The creational material is preserved and transformed — resurrection theology (continuity + transformation) applied to the entire cosmos.');

-- ═══ Revelation Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Revelation', 22, 'kids', 1, 'What flows through the middle of the city?', 'A pure river of water of life, clear as crystal, flowing from God''s throne', 'A river of milk', 'A stream of gold', 'A river of honey', 'a', 'Revelation 22:1 — "And he shewed me a pure river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb."'),
('Revelation', 22, 'kids', 2, 'What grows on either side of the river?', 'The tree of life, which bears twelve kinds of fruit and whose leaves are for the healing of the nations', 'Ordinary oak trees', 'Palm trees', 'Rose bushes', 'a', 'Revelation 22:2 — "In the midst of the street of it, and on either side of the river, was there the tree of life, which bare twelve manner of fruits, and yielded her fruit every month: and the leaves of the tree were for the healing of the nations."'),
('Revelation', 22, 'kids', 3, 'What does Jesus say at the very end of the book?', '"Surely I come quickly" — and John replies "Amen. Even so, come, Lord Jesus"', '"Goodbye forever"', '"I will return in a thousand years"', '"Forget about me"', 'a', 'Revelation 22:20 — "He which testifieth these things saith, Surely I come quickly. Amen. Even so, come, Lord Jesus."'),
-- Teens
('Revelation', 22, 'teens', 1, 'What is no longer in the new Jerusalem?', 'No more curse — the curse from Eden is completely removed', 'No more music', 'No more colours', 'No more friendship', 'a', 'Revelation 22:3 — "And there shall be no more curse: but the throne of God and of the Lamb shall be in it; and his servants shall serve him."'),
('Revelation', 22, 'teens', 2, 'What will God''s servants see?', 'His face — they shall see His face, and His name shall be in their foreheads', 'Only His shadow', 'Only His throne', 'Only His hands', 'a', 'Revelation 22:4 — "And they shall see his face; and his name shall be in their foreheads."'),
('Revelation', 22, 'teens', 3, 'What invitation is given at the end of the book?', '"The Spirit and the bride say, Come. And let him that heareth say, Come. And let him that is athirst come. And whosoever will, let him take the water of life freely"', '"Only the worthy may come"', '"Wait until you are called"', '"Stay where you are"', 'a', 'Revelation 22:17 — "And the Spirit and the bride say, Come. And let him that heareth say, Come. And let him that is athirst come. And whosoever will, let him take the water of life freely."'),
('Revelation', 22, 'teens', 4, 'What warning is given about adding to or taking away from this book?', 'If anyone adds to these words, God will add plagues to him; if anyone takes away, God will take away his part from the book of life and the holy city', 'There is no warning', 'Only scholars are warned', 'The warning applies to other books', 'a', 'Revelation 22:18-19 — "If any man shall add unto these things, God shall add unto him the plagues that are written in this book: And if any man shall take away from the words of the book of this prophecy, God shall take away his part out of the book of life."'),
('Revelation', 22, 'teens', 5, 'What does Jesus call Himself in the last chapter?', '"I am the root and the offspring of David, and the bright and morning star"', '"I am a great teacher"', '"I am the king of Israel only"', '"I am the last prophet"', 'a', 'Revelation 22:16 — "I Jesus have sent mine angel to testify unto you these things in the churches. I am the root and the offspring of David, and the bright and morning star."'),
-- Adults
('Revelation', 22, 'adults', 1, 'How does the river of life and tree of life reverse the Genesis curse?', 'In Eden, the tree of life was guarded by cherubim after the fall (Genesis 3:22-24); now access is fully restored — the river of life (cf. Ezekiel 47:1-12; Genesis 2:10) flows freely, the tree bears continuous fruit, and its leaves heal the nations; every consequence of the fall is undone', 'There is no Genesis connection', 'The tree is different from Eden''s', 'The curse remains partially', 'a', 'Revelation 22:1-3 — The river echoes Eden''s river (Genesis 2:10) and Ezekiel''s temple river (47:1-12). The tree of life (Genesis 2:9; 3:22-24) is now accessible. "No more curse" (v.3) explicitly reverses Genesis 3:17. The Bible ends where it began — paradise, but perfected.'),
('Revelation', 22, 'adults', 2, 'What does "they shall see his face" (the beatific vision) represent theologically?', 'The ultimate fulfilment of human destiny — Moses was denied God''s face (Exodus 33:20); the psalmist longed for it (Psalm 17:15; 27:4); Jesus promised it (Matthew 5:8); now it is realised; the beatific vision is unmediated communion with God — the supreme blessing of the new creation', 'A metaphorical expression only', 'Seeing a symbol of God', 'A temporary experience', 'a', 'Revelation 22:4 — "They shall see his face." Exodus 33:20 — "There shall no man see me, and live." Psalm 17:15 — "I shall behold thy face in righteousness." Matthew 5:8 — "The pure in heart... shall see God." What was forbidden becomes the eternal privilege of the redeemed.'),
('Revelation', 22, 'adults', 3, 'How does "the root and the offspring of David" compress Christ''s identity?', 'He is simultaneously David''s ancestor (root — the source from which David sprang, alluding to Isaiah 11:1,10 and His pre-existence) and David''s descendant (offspring — born in David''s line, fulfilling 2 Samuel 7:12-13); He is both before David and after David — eternal God and incarnate man', 'He is only David''s descendant', 'He is only David''s ancestor', 'The title has no christological significance', 'a', 'Revelation 22:16 — "I am the root and the offspring of David." Root = source/origin (pre-existence, deity); offspring = descendant (incarnation, humanity). The dual title echoes Jesus'' question in Matthew 22:42-45 — how can David''s son also be David''s Lord?'),
('Revelation', 22, 'adults', 4, 'How does "the Spirit and the bride say, Come" function as the book''s final invitation?', 'It is a multilayered invitation: (1) the Spirit and bride invite Christ to return ("Come"), (2) hearers pass the invitation along, (3) the thirsty are invited to come to Christ for the water of life; it combines Maranatha eschatology with evangelistic offer — longing for Christ''s return and welcoming the lost simultaneously', 'It is addressed only to angels', 'It invites people to a literal feast', 'It is a command to leave', 'a', 'Revelation 22:17 — The threefold "Come" addresses both Christ (eschatological longing) and the unconverted (evangelistic invitation). The Spirit''s internal call and the bride''s external testimony unite in offering the water of life "freely" (dōrean — as a gift, cf. Romans 3:24).'),
('Revelation', 22, 'adults', 5, 'What does the warning against adding to or taking from "this prophecy" protect?', 'It protects the integrity of the prophetic revelation — echoing Deuteronomy 4:2 and 12:32 (do not add to or diminish God''s commands); it treats Revelation as authoritative Scripture on par with Torah and demands that its message be preserved intact', 'It applies to all books ever written', 'It is a later scribal addition', 'It protects only the last chapter', 'a', 'Revelation 22:18-19 — "If any man shall add... if any man shall take away." Cf. Deuteronomy 4:2; 12:32; Proverbs 30:6. The imprecatory warnings (plagues added, name removed) make altering the text an act of sacrilege — the strongest possible canonical protection.'),
('Revelation', 22, 'adults', 6, 'How does "Surely I come quickly" (Erchomai tachy) summarise Revelation''s eschatology?', 'It is Christ''s third and final promise of imminent return (cf. 22:7,12,20); "quickly" (tachy) emphasises suddenness and certainty rather than chronological immediacy — when Christ comes, He comes swiftly and decisively; the church lives in perpetual readiness', 'It means within one calendar year', 'It was already fulfilled', 'It is uncertain', 'a', 'Revelation 22:20 — "Surely I come quickly." The adverb tachy means "soon/suddenly/swiftly" — emphasising the certainty and sudden nature of the return rather than specifying a timeline. The church''s response — "Even so, come, Lord Jesus" — is the final prayer of Scripture.'),
('Revelation', 22, 'adults', 7, 'How does Revelation 22 bring the entire biblical canon to its intended conclusion?', 'It reverses every curse of Genesis 3 (no more curse), restores Eden''s features (river, tree of life), fulfils Israel''s hopes (new Jerusalem, nations healed), completes Christ''s work (throne of God and the Lamb), and answers the Bible''s first question of broken fellowship with the ultimate answer: "They shall see his face"', 'Revelation is disconnected from Genesis', 'The Bible has no unified narrative', 'Only the New Testament matters', 'a', 'Revelation 22:1-5 reverses Genesis 3 point by point: river (Gen 2:10), tree of life (Gen 2:9; 3:24), no curse (Gen 3:17), God''s presence (Gen 3:8), seeing God''s face (Gen 3:23-24). The Bible''s narrative arc from creation to fall to redemption to restoration is complete.'),
('Revelation', 22, 'adults', 8, 'What does "The grace of our Lord Jesus Christ be with you all" reveal about Revelation''s genre and purpose?', 'The epistolary closing (like Paul''s letters) reminds readers that Revelation is not merely apocalyptic spectacle but a pastoral letter to churches — it begins (1:4) and ends with grace; despite the terrifying judgments, the final word is grace, framing the entire book within the gospel', 'It is a standard formality', 'Revelation is not a letter', 'Grace is irrelevant to Revelation', 'a', 'Revelation 22:21 — "The grace of our Lord Jesus Christ be with you all. Amen." Revelation opens as a letter (1:4 — "Grace be unto you, and peace") and closes as one. The entire apocalypse is bookended by grace — the first and last word to the churches is the gospel of grace.');
